import{_ as a,o as e,c as o,j as r,a as b,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const T=JSON.parse('{"title":"1.Try another story","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/Try another story/1.Try another story.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/Try another story/1.Try another story.md"}'),n={name:"4.资源分区/6.技艺及称号/通用及综合类/Try another story/1.Try another story.md"};function p(y,t,h,_,d,l){return e(),o("div",null,[...t[0]||(t[0]=[r("h1",{id:"_1-try-another-story",tabindex:"-1"},[b("1.Try another story "),r("a",{class:"header-anchor",href:"#_1-try-another-story","aria-label":'Permalink to "1.Try another story"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),s('<h1 id="try-another-story" tabindex="-1">Try another story <a class="header-anchor" href="#try-another-story" aria-label="Permalink to &quot;Try another story&quot;">​</a></h1><p>Try another story<br> （试试另一个故事。）<br> 这是没有被圆环之理所干涉，所存留下来的某个世界的故事，在漫漫长夜外，如同奇迹般的故事。<br> 微小的巧合开始了新的转动，无数的选择当中，那是一度被舍弃的光景，和坚强的朋友们一同战斗，跨越魔女之夜的伟业与故事。</p><p>“《魔法记录》，《魔法少女织莉子》，《剧场版：叛逆的物语》，《魔法少女和美》，《Mobage版：魔法少女小圆》，《神圣之门》，《魔法少女铃音》，《魔法少女小圆：Online版》，《杀戮幻影》，《魔法少女贞德》等等，还有完全没见过的原创角色……说实话，就连我也搞不懂这个友好到过分的时间线是什么情况。”<br> ——by恶魔晓美焰</p><p>前提：无。（对于丘比而言，感情的起伏才是根本，因此在特殊情况下也会男性的魔法少女。）<br> 特殊的是，具有魔法少女Dark Ness改造的轮回者购买这个资源时不会获得灵魂宝石，但可以获得灵魂宝石相关的好处，会如常开启能量池与获得相应的能力。</p><p>签订契约<br> 价格：D+1000<br> 描述：你的才能被主神发掘，获得了成为魔法少女的可能，虽然主神的契约并不能提供完全的效果，但也因此失去了许多不利之处。<br> 有趣的是，轮回者本身的性质在某些方面与魔法少女极其相似——比如说，不是人。</p><p>魔法契约：仁慈或是陷阱，希望或是绝望，成为魔法少女本身随着愿望而开始，愿望也同样决定了魔法少女的能力。<br> 购买该兑换的D级时，你可以许下一个愿望，虽然愿望不就被实现，但主神会将你的愿望折算为初始能力赋予给你，你自行选择以下一项效果获得：</p><p>1.获得装备：你下一个购买的装备成为你的“魔法少女专属装备”。若是武器，则你在使用其时，每有1点传奇感知，武器的高速增加1点。每有1点传奇风度，武器的破甲增加1点。每有1点传奇决心，武器的破魔增加1点。<br> ——<br> 若是防具，则如同武器一样根据对应的传奇属性获得抵高速/抵破甲/抵破魔的效果。<br> 其他人使用专属装备时，无法获得专属装备的任何效果。<br> 2.治愈伤病：你免疫C级别疾病/毒素来源的负面效果，并获得1点再生，这一再生等同于快速医疗的效果，具有20点医疗池点数，但每生效一次，需要消耗1点SG，你可以令其不生效。你可以使用一个花招动作将这一能力共享给触及范围内的一名其他单位，持续一场景。<br> 3.降低自身存在感：这既是愿望也是能力。你的存在感将大幅降低，这视为一个D级别特异本质反侦测效果。<br> 此外，你在隐秘检定上获得2DP的表现加值，你的反侦测能力无法关闭，但免疫同等级心灵来源影响的队友可以与你正常交流。<br> 4.重新来过：每日二次，你需要在获得时指定一项检定（包括机运骰，不包括基因锁），可以选择发动本效果重骰检定，必须接受最后一次的结果。<br> 5.传播消息：你可以消耗时间在一处传播和收集消息，一般来说，每消耗一小时就能在半径1000米范围内留下声望，随工作时长扩张，上限范围是你的传奇操纵*1000米。<br> 在工作时长中，你可以同时进行交际（收集情报）而不会消耗额外时间，也无需进行正常的互动交流或对于合适场景的需求，这是一个C级影响心灵来源的思维控制能力，意味着对方会有意思的忽略你不合时宜的出现在这里传播消息或者是搜查情报，但如果会大幅度影响到对方的基本利益，依旧会被察觉到问题。<br> 活动于范围内，或与范围内生物有较大交情的目标（ST判定），对你的初始态度提升1级，无法从极端态度状态下提升或是提高到极端态度，该效果不会和其他类似效果叠加，也不能重复生效。<br> 你也可以选择诽谤特定目标，使范围内的单位对特定单位的好感降低1级，无法从极端态度下降也无法降低到极端态度，其他限制等同于提升态度一样，而且需要你使用社交检定在对被影响者的社交对抗中取得至少1个成功数，这是一个C级影响心灵来源的思维控制效果。<br> 6.守护他人：当你的敏感范围内有同伴死去时，你的SG能量池上限将增加3点，每影片只能触发一次这个效果。<br> 如果该同伴具有至少一项主神空间来源的D级技艺，则你随机获得不会导致爆体的一项，这会使得其失去该能力，当其复活时也不会复原，以此为基础的能力失效到再次强化，每影片只能触发一次这个效果。</p><p>选开（默认不开）：若ST允许，你也可以对NPC使用这个效果，但要求NPC的关系抵达其自愿交给你的标准程度。</p><p>灵魂宝石：你获得了一枚灵魂宝石，颜色是黑色以外任意的颜色，通常根据你的兑换倾向和性格决定颜色。<br> 灵魂宝石的颜色会根据SG剩余的数值而逐渐转变为黑色，为零时化作纯粹的黑色，恢复能量时会逐渐转变为之前的颜色。</p><p>由于你的契约签订者是主神，即使你的灵魂宝石被摧毁也不会怎么样，SG耗尽也不会变成魔女，被摧毁的灵魂宝石会在次日零点重新生成在身边，宝石视为同等级物品，材质为金刚石。<br> 你与其他魔法少女不存在心灵感应能力，但在针对魔法少女小圆系列的魔女时，依旧具有感知和正常进入魔女结界的能力。</p><p>SG：SG是一种变体魔力能量池，以决心+风度决定上限。<br> SG每日将自动恢复三倍上限的数量，平摊到每个小时计算恢复，因此没有其他基础恢复方式。<br> 基本用法：支付1点SG，你可以在基础移动速度上获得5米提升，或在单一生理属性检定上获得1点增强加值，持续1轮，同时只能生效一种效果。</p><p>魔法资质：你获得了购买相关装备、技艺，以及其他内容的资格，任何没有购买主干的单位是无法使用相关能力的，无论是什么原因。<br> 你必须在购买时选择自身对应的颜色倾向，你可以购买对应颜色倾向的装备，技艺，合体技与相关能力等内容。</p><p>熟练的魔法少女<br> 价格：C+1000<br> 描述：大部分成为魔法少女的少女会因为因果量不足的问题而导致愿望的不完全实现，她们往往会很快陷入绝望或是在与初次和魔女进行战斗中被杀死。<br> 没有很快绝望且有着能获取悲叹之种能力的魔法少女，其实是相当罕见的存在。<br> 无魂之躯：将灵魂从身体中抽出，得到的结果就是灵魂宝石。因此灵魂宝石破碎才会导致魔法少女的死亡，但作为轮回者而言，只是得到了相应的好处。<br> 你免疫疾病和毒素；你不再需要食物、饮水、睡眠和呼吸来维持生命，当然你依旧可以正常使用这些机能，需要计算等级的场合这些能力视为C级免疫效果。<br> 魔化武器：你可以向武器注入魔力，这是一种魔法少女的战斗方式。SG上的基础用法将改为“每消费2点能量，提升武器伤害1L，重复3次后额外增加1L”，这种用法无需消费动作，效果持续一场景，无法重复使用基础用法叠加这个效果。<br> 此外，这种基础用法具有能量消耗上限，消耗上限为6点SG。</p><p>战斗的理由<br> 价格：B+2000<br> 描述：魔法少女的真实即是如此，身体已然不是自己曾经认识的模样，当死亡与绝望如影随形之时，却不是所有人会放弃自己所战斗的理由。<br> 但请谨记，对于丘比而言，希望越大，最终的绝望也会越大，这正是其选择放任的目的。<br> 提升-灵魂宝石：只要你的灵魂宝石没有被摧毁，你在死后就不会真正意义上的死亡，而是转变为以灵魂宝石的形式存在，可以观察外界，或者消耗1点结构值获得一天的可移动能力，移动速度等同于你生前的基础移动速度。<br> 此时灵魂宝石的获得等同你意志值的结构值，若结构值被清空即宝石破碎，你立刻真正死亡，但如果能以这样状态保持一个月的存活或是回到主神空间，你就能重塑身体从灵魂宝石所在的位置复活，这是一个B级复活能力。<br> 善战：只要使用魔力就必定会积累污秽，在没有主神的时候，只有击杀魔女获得悲叹之种才能清除污秽，何况魔女也并非必然掉落污秽之种。<br> 如此逼迫致使所有活下来的魔法少女都是善战之人，当然，她们还有其他选择……那就是放任使魔袭击人类成长为新生魔女来收割，或是袭击作为魔法少女的同类掠夺悲叹之种。<br> 现在开始，每经历一场赢得同等级的以杀死对方为目标的战斗后（任何切磋性质的战斗无效），你都可以获得2点XP用于购买下属任意相关能力和效果，这个效果每影片最多生效5次。</p><p>觉醒<br> 价格：A+4000<br> 描述：“（能量）转换”、“具现”、“（污秽）回收”，本应建立于对于丘比系统的掠夺，但主神也能提供一样的服务。回收污秽，将污秽作为燃料，显现出魔女化身，虽然没有真正的魔女强大但是也不会导致灵魂宝石的破碎与死亡。<br> 当然，作为轮回者而言即使展开魔女化身也不能立刻将魔力恢复完整，只是能获得对应的部分能力。<br> 魔女化身：每日一次，若你的SG能量池剩余不超过上限的一半，且在此场景中消耗了至少1/3的SG能量池。则消耗所有剩余SG能量，消费一个标准动作化身魔女，化身魔女后你的体积将增加你的传奇决心*5点，增加的体积不会带来任何好处，只是看起来变大了，如同虚影一样包裹着你的本体。<br> 这会以你为中心在原地展开一个特殊的魔女结界，魔女结界视为A级时空来源的异空间效果，附带同等级免疫传送能力，不免疫别人通过传送进入魔女结界，但影响别人利用传送脱离魔女结界。<br> 魔女结界内的天气与环境由你在购买时自行抉择，这需要从环境规则中挑选合计不超过A级的环境效果，会对除你之外的所有角色生效，来源始终视为A级时空来源的环境效果。<br> 拉入其他人需要在化身魔女时对结界覆盖范围内的所有单位进行一次普通攻击检定，目标以反射豁免出目，失败则被拉入魔女结界。<br> 魔女结界的范围等同于你的决心*50米，在你使用该系列相关技能时，可以将相关技能射程提升至等同魔女结界的范围或自身敏感范围（取低），同时在攻击时攻击等同魔女结界范围内的所有敌对单位。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',17)])])}const c=a(n,[["render",p]]);export{T as __pageData,c as default};
